// NocoDB sends: { type, data: { rows: [newRow], previous_rows: [oldRow] } }
// We also support direct POST: { client_id, order_id, status, customer_phone, customer_name, ... }
const b = $('Webhook · Order Event').first().json.body || $('Webhook · Order Event').first().json;

let row = {};
if (b.data && b.data.rows && b.data.rows[0]) {
  row = b.data.rows[0];
} else {
  row = b; // direct POST
}

const prevStatus = (b.data?.previous_rows?.[0]?.status || '').toLowerCase();
const newStatus  = (row.status || '').toLowerCase();
const clientId   = String(row.client_id || b.client_id || '');
const phone      = (row.customer_phone || '').replace(/[^0-9+]/g, '').replace(/^\+/, '').replace(/^00/, '');
const customerName = row.customer_name || 'Customer';
const orderId    = row.order_id || row.Id || '';
const items      = row.items || '';

// Only act on status transitions
const RECEIVED  = new Set(['received','confirmed','processing','accepted']);
const DELIVERED = new Set(['delivered','completed','done']);

let reminderType = null;
if (RECEIVED.has(newStatus) && !RECEIVED.has(prevStatus)) reminderType = 'received';
if (DELIVERED.has(newStatus) && !DELIVERED.has(prevStatus)) reminderType = 'delivered';

if (!reminderType)  return []; // no reminder needed
if (!phone)         return []; // no phone to send to
if (!clientId)      return []; // no client

return [{ json: { clientId, phone, customerName, orderId, items, newStatus, reminderType } }];

// Sends straight to Meta's Graph API using the client's own connected WhatsApp Business
// number — no Chatwoot dependency, and templates are required anyway once a contact is
// outside the 24h session window (which is the norm for delivery/status notifications).
const ev = $('Code · Parse Event').first().json;
const t  = $input.first().json;

if (!t.wa_phone_id || !t.wa_token) return []; // WhatsApp not connected for this client

let templatesCfg = {};
try { templatesCfg = JSON.parse(t.ecom_wa_templates || '{}').config || {}; } catch(e) {}

const cfg = templatesCfg[ev.reminderType];
if (!cfg || !cfg.name) return []; // no template configured for this event

const valueMap = {
  customer_name: ev.customerName,
  order_id: String(ev.orderId),
  items: ev.items,
  review_link: t.review_link || '',
  store_name: t.client_name || ''
};
const parameters = (cfg.params || []).map(key => ({ type: 'text', text: String(valueMap[key] || '') }));
const components = parameters.length ? [{ type: 'body', parameters }] : [];

return [{ json: {
  phone: ev.phone,
  wa_phone_id: t.wa_phone_id,
  wa_token: t.wa_token,
  template_name: cfg.name,
  template_lang: cfg.lang || 'en',
  components
} }];
